import React, { Component } from "react";
import Link from "next/link";
import { connect } from "react-redux";
import { Button } from "antd";

class Navigation extends Component {
  render() {
    return (
      <div
        style={{
          width: "100%",
          height: "5vh",
          display: "flex",
          flexDirection: "row",
          justifyContent: "space-between",
          padding: "1vw"
        }}
      >
        <Button type="link" style={{ fontSize: "1vw", color: "black" }}>
          jackieni.io
        </Button>

        <div
          style={{
            display: "flex",
            flexDirection: "row",
            justifyContent: "space-evenly"
          }}
        >
          <Button type="link" style={{ fontSize: "1vw", color: "black" }}>
            Memes
          </Button>

          <Button type="link" style={{ fontSize: "1vw", color: "black" }}>
            Projects
          </Button>

          <Button type="link" style={{ fontSize: "1vw", color: "black" }}>
            Thoughts
          </Button>

          <Button
            style={{
              backgroundColor: "black",
              color: "white"
            }}
          >
            <div
              style={{
                display: "flex",
                alignItems: "center"
              }}
            >
              <img
                src={"/static/whiteBatarang.png"}
                style={{ width: "1.6vw", color: "white" }}
              />
              <div style={{ fontSize: "1vw", marginLeft: "0.4vw" }}>
                Batmode
              </div>
            </div>
          </Button>
        </div>
      </div>
    );
  }
}

export default connect(
  null,
  { changeBatmode }
)(Navigation);
